import { ArrowUpRight, ArrowDownRight, Minus, Globe, MessageSquare, AlertCircle } from 'lucide-react';
import TrendChart from './TrendChart';
import TrendMap from './TrendMap';

interface TrendDetailProps {
  trend: Trend;
  onClose: () => void;
}

const TrendDetail: React.FC<TrendDetailProps> = ({ trend, onClose }) => {
  const getVelocityColor = (v: string) => {
    switch (v) {
      case 'Rising': return 'bg-green-100 text-green-700 border-green-200';
      case 'Declining': return 'bg-red-100 text-red-700 border-red-200';
      default: return 'bg-gray-100 text-gray-700 border-gray-200';
    }
  };

  // Helper to identify Media Prima sources
  const isMediaPrima = (name: string, url: string) => {
    const keywords = [
      'media prima', 'nst', 'new straits times', 'bharian', 'berita harian', 
      'hmetro', 'harian metro', 'says', 'ohbulan', 'seismik', 'tonton', 'tv3', '8tv', 'tv9'
    ];
    const text = `${name} ${url}`.toLowerCase();
    return keywords.some(k => text.includes(k));
  };

  return (
    <div className="flex flex-col lg:flex-row gap-6">
      {/* Left Column: Analytics & Info */}
      <div className="flex-1 space-y-6 min-w-0"> {/* min-w-0 prevents flex items from overflowing */}

        {/* Header Card */}
        <div className="bg-white p-4 sm:p-6 rounded-xl shadow-sm border border-slate-200">
          <div className="flex justify-between items-start mb-4">
            <div>
              <div className="flex items-center gap-2 mb-2">
                <span className={`px-2 py-0.5 rounded text-xs font-semibold uppercase tracking-wider ${getVelocityColor(trend.velocity)}`}>
                  {trend.velocity}
                </span>
                <span className="text-xs text-slate-400 font-mono">ID: {trend.id}</span>
              </div>
              <h2 className="text-xl sm:text-2xl font-bold text-slate-900 leading-tight">{trend.title}</h2>
            </div>
            <div className="flex flex-col items-end shrink-0 ml-4">
                <div className="text-3xl font-black text-slate-800">{trend.score}</div>
                <div className="text-xs text-slate-500 uppercase font-semibold text-right">Signal<br/>Score</div>
            </div>
          </div>

          <p className="text-slate-600 mb-6 leading-relaxed text-sm sm:text-base">{trend.summary}</p>

          <div className="bg-amber-50 border border-amber-200 rounded-lg p-4">
            <h4 className="text-sm font-bold text-amber-900 flex items-center gap-2 mb-2">
              <AlertCircle size={16} /> Why it matters
            </h4>
            <p className="text-sm text-amber-800 leading-relaxed">
              {trend.reasoning}
            </p>
          </div>
        </div>

        {/* Chart Card */}
        <div className="bg-white p-4 sm:p-6 rounded-xl shadow-sm border border-slate-200 overflow-hidden">
            <h3 className="font-semibold text-slate-800 mb-2">Signal Velocity (Last 5 Days)</h3>
            <TrendChart data={trend.history} color={trend.velocity === 'Rising' ? '#22c55e' : '#3b82f6'} />
        </div>

        {/* Sources Card */}
        <div className="bg-white p-4 sm:p-6 rounded-xl shadow-sm border border-slate-200">
           <h3 className="font-semibold text-slate-800 mb-4 flex items-center gap-2">
             <Globe size={18} /> Signal Sources
           </h3>
           <div className="space-y-3">
             {trend.sources.map((source, idx) => (
               <a 
                 key={idx} 
                 href={source.url}
                 target="_blank"
                 rel="noopener noreferrer"
                 className="block group p-3 rounded-lg border border-slate-100 hover:border-blue-200 hover:bg-blue-50 transition-all"
               >
                 <div className="flex justify-between items-start gap-2">
                    <span className="text-sm font-medium text-slate-700 group-hover:text-blue-700 line-clamp-1 break-all sm:break-normal">{source.title}</span>
                    <ArrowUpRight size={14} className="text-slate-300 group-hover:text-blue-500 opacity-0 group-hover:opacity-100 transition-opacity shrink-0" />
                 </div>
                 <div className="mt-1 flex flex-wrap items-center gap-2 text-xs text-slate-500">
                    <span className="font-semibold text-slate-600">{source.sourceName}</span>
                    {isMediaPrima(source.sourceName, source.url) && (
                      <>
                        <span className="hidden sm:inline">•</span>
                        <span className="text-blue-600 font-bold block sm:inline mt-1 sm:mt-0">Media Prima Network</span>
                      </>
                    )}
                 </div>
               </a>
             ))}
             {trend.sources.length === 0 && (
                <div className="text-sm text-slate-400 italic">No direct sources linked via simulated output.</div>
             )}
           </div>
        </div>
      </div>

      {/* Right Column: Visuals & Map */}
      <div className="w-full lg:w-80 flex flex-col gap-6 shrink-0">
         <div className="h-64 sm:h-80 w-full">
            <TrendMap locationName={trend.location || ''} trendTitle={trend.title} />
         </div>

         {/* Context Card */}
         <div className="bg-gradient-to-br from-indigo-600 to-purple-700 rounded-xl shadow-lg p-6 text-white">
            <h3 className="font-bold text-lg mb-2 flex items-center gap-2">
                <MessageSquare size={18} />
                Analyst Note
            </h3>
            <p className="text-indigo-100 text-sm leading-relaxed mb-4">
                This trend has clustered across {trend.sources.length + 3} distinct data points today.
            </p>
            <div className="flex flex-wrap gap-2">
                <span className="px-2 py-1 bg-white/10 rounded text-xs border border-white/20">High Engagement</span>
                <span className="px-2 py-1 bg-white/10 rounded text-xs border border-white/20">Sentiment: Mixed</span>
            </div>
         </div>
      </div>
    </div>
  );
};

export default TrendDetail;

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { FilterState, Trend } from "../types";

// Using 'gemini-3-flash-preview' for complex text tasks + search grounding.
// Using 'gemini-2.5-flash' specifically for Maps Grounding as required by the documentation.
const MODEL_NAME = 'gemini-3-flash-preview'; 
const MAPS_MODEL_NAME = 'gemini-2.5-flash';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * This function simulates the "Scraping" and "Clustering" logic.
 * 1. It uses the `googleSearch` tool to find real-time articles.
 * 2. It asks the model to cluster these into JSON.
 */
export const detectTrends = async (filters: FilterState): Promise<Trend[]> => {
  const { country, date, category } = filters;

  // 1. Dynamic Search Context based on Category
  let searchContext = "top trending news stories and high-impact headlines";
  if (category !== 'All') {
    searchContext = `latest trending news, headlines, and viral topics specifically related to ${category}`;
  }

  // 2. Dynamic Source Hints based on Country
  // This prevents the model from looking for Malaysian sources when the user wants US/UK news.
  let sourceHint = 'Look for reputable, major news outlets and reliable local media.';
  let locationExamples = 'capital cities or major economic hubs';

  if (country === 'Malaysia') {
    sourceHint = 'Look for reputable sources like "Media Prima", "New Straits Times", "Berita Harian", "Harian Metro", "The Star", "Says", "Bernama".';
    locationExamples = 'e.g. "Kuala Lumpur", "Johor Bahru", "Penang"';
  } else if (country === 'United States') {
    sourceHint = 'Look for reputable sources like "CNN", "New York Times", "Reuters", "Bloomberg", "The Verge", "WSJ", "Fox News", "NPR".';
    locationExamples = 'e.g. "New York", "San Francisco", "Washington D.C."';
  } else if (country === 'United Kingdom') {
    sourceHint = 'Look for reputable sources like "BBC", "The Guardian", "Sky News", "Financial Times", "Telegraph".';
    locationExamples = 'e.g. "London", "Manchester", "Edinburgh"';
  } else if (country === 'Indonesia') {
    sourceHint = 'Look for reputable sources like "Kompas", "Detik", "Tempo", "Jakarta Post".';
    locationExamples = 'e.g. "Jakarta", "Bali", "Surabaya"';
  } else if (country === 'Singapore') {
    sourceHint = 'Look for reputable sources like "Straits Times", "CNA", "Today Online".';
    locationExamples = 'e.g. "Singapore", "Changi"';
  }

  // 3. Strict Prompting for Truthfulness
  const prompt = `
    Role: Senior Media Analyst & Fact Checker.
    Current Date: ${date}.
    Target Region: ${country}.
    Sector Focus: ${category}.

    MISSION:
    1. EXECUTE A SEARCH: Use the 'googleSearch' tool to find the ${searchContext} in ${country}.
       - ${sourceHint}
       - CRITICAL: Focus strictly on news relevant to ${country}. Do not include unrelated international news unless it has a major direct impact on ${country}.

    2. CLUSTER: Group results into exactly 5 distinct "Trend Signals".

    3. JSON OUTPUT: Return a JSON array.

    CRITICAL RULES FOR "SOURCES":
    - ABSOLUTE TRUTH ONLY: You must ONLY include sources where the 'googleSearch' tool provided a specific URL.
    - NO GUESSING: If you saw a headline but no direct URL, DO NOT make up a link. Just omit that source from the list.
    - VALIDITY CHECK: Better to have 1 real source than 5 broken links.

    For each trend, provide:
       - 'velocity': 'Rising' (new/breaking), 'Stable' (ongoing), 'Declining' (old).
       - 'location': A specific city/state in ${country} (${locationExamples}) if relevant. Default to "${country}" if generic.
  `;

  const responseSchema: Schema = {
    type: Type.ARRAY,
    items: {
      type: Type.OBJECT,
      properties: {
        id: { type: Type.STRING },
        title: { type: Type.STRING },
        summary: { type: Type.STRING },
        score: { type: Type.NUMBER },
        category: { type: Type.STRING, enum: ['Politics', 'Tech', 'Business', 'Lifestyle', 'Entertainment'] },
        velocity: { type: Type.STRING, enum: ['Rising', 'Stable', 'Declining'] },
        reasoning: { type: Type.STRING },
        location: { type: Type.STRING },
        sources: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              url: { type: Type.STRING },
              sourceName: { type: Type.STRING },
            }
          }
        },
        history: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              date: { type: Type.STRING },
              score: { type: Type.NUMBER }
            }
          }
        }
      }
    }
  };

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: responseSchema
      }
    });

    let text = response.text;
    if (!text) throw new Error("No data returned from AI");

    // Clean up if the model wraps the response in Markdown code blocks
    text = text.replace(/^```json\s*/, "").replace(/```$/, "").trim();

    let trends: Trend[];
    try {
      trends = JSON.parse(text) as Trend[];
    } catch (e) {
      console.error("Failed to parse JSON", text);
      throw new Error("AI returned malformed JSON");
    }

    if (!Array.isArray(trends)) {
      return [];
    }

    // Post-processing safety check to ensure we don't crash the UI with bad data
    return trends.map((t, index) => ({
      ...t,
      id: t.id || `trend-${index}`,
      sources: t.sources || [] // Ensure sources is always an array
    }));

  } catch (error) {
    console.error("Error detecting trends:", error);
    throw error;
  }
};

/**
 * Performs a Maps Grounding query for a specific trend to get visual context.
 */
export const getTrendLocation = async (trendTitle: string, locationHint: string): Promise<any> => {
  try {
    const response = await ai.models.generateContent({
      model: MAPS_MODEL_NAME,
      contents: `Show me exactly where ${locationHint} is, related to the news topic: "${trendTitle}".`,
      config: {
        tools: [{ googleMaps: {} }],
      }
    });

    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    const mapChunk = chunks?.find(c => c.maps);

    if (mapChunk && mapChunk.maps) {
      return {
        web_url: mapChunk.maps.googleMapsUri,
        title: mapChunk.maps.placeId
      };
    }
    return null;

  } catch (error) {
    console.error("Maps error", error);
    return null;
  }
};

