  } else if (country === 'Indonesia') {
    sourceHint = 'Look for reputable sources like "Kompas", "Detik", "Tempo", "Jakarta Post".';
    locationExamples = 'e.g. "Jakarta", "Bali", "Surabaya"';
  } else if (country === 'Singapore') {
    sourceHint = 'Look for reputable sources like "Straits Times", "CNA", "Today Online".';
    locationExamples = 'e.g. "Singapore", "Changi"';
  }

  // 3. Strict Prompting for Truthfulness
  const prompt = `
    Role: Senior Media Analyst & Fact Checker.
    Current Date: ${date}.
    Target Region: ${country}.
    Sector Focus: ${category}.

    MISSION:
    1. EXECUTE A SEARCH: Use the 'googleSearch' tool to find the ${searchContext} in ${country}.
       - ${sourceHint}
       - CRITICAL: Focus strictly on news relevant to ${country}. Do not include unrelated international news unless it has a major direct impact on ${country}.

    2. CLUSTER: Group results into exactly 5 distinct "Trend Signals".

    3. JSON OUTPUT: Return a JSON array.

    CRITICAL RULES FOR "SOURCES":
    - ABSOLUTE TRUTH ONLY: You must ONLY include sources where the 'googleSearch' tool provided a specific URL.
    - NO GUESSING: If you saw a headline but no direct URL, DO NOT make up a link. Just omit that source from the list.
    - VALIDITY CHECK: Better to have 1 real source than 5 broken links.

    For each trend, provide:
       - 'velocity': 'Rising' (new/breaking), 'Stable' (ongoing), 'Declining' (old).
       - 'location': A specific city/state in ${country} (${locationExamples}) if relevant. Default to "${country}" if generic.
       - 'history': A simulated array of 5 data points showing the trend score over the last 5 days (e.g. dates MM-DD).
  `;

  const responseSchema: Schema = {
    type: Type.ARRAY,
    items: {
      type: Type.OBJECT,
      properties: {
        id: { type: Type.STRING },
        title: { type: Type.STRING },
        summary: { type: Type.STRING },
        score: { type: Type.NUMBER },
        category: { type: Type.STRING, enum: ['Politics', 'Tech', 'Business', 'Lifestyle', 'Entertainment'] },
        velocity: { type: Type.STRING, enum: ['Rising', 'Stable', 'Declining'] },
        reasoning: { type: Type.STRING },
        location: { type: Type.STRING },
        sources: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              url: { type: Type.STRING },
              sourceName: { type: Type.STRING },
            }
          }
        },
        history: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              date: { type: Type.STRING },
              score: { type: Type.NUMBER }
            }
          }
        }
      }
    }
  };

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: responseSchema
      }
    });

    let text = response.text;
    if (!text) throw new Error("No data returned from AI");

    // --- Robust JSON Cleaning ---
    // Sometimes the model wraps JSON in markdown or adds conversational text.
    // We strictly extract the JSON array structure.

    // 1. Remove Markdown code blocks
    text = text.replace(/```json/g, "").replace(/```/g, "");

    // 2. Find the JSON array
    const firstBracket = text.indexOf('[');
    const lastBracket = text.lastIndexOf(']');

    if (firstBracket !== -1 && lastBracket !== -1) {
      text = text.substring(firstBracket, lastBracket + 1);
    } else {
      // Fallback: if no array brackets found, it's definitely invalid
      console.warn("Raw AI response did not contain a JSON array:", text);
      throw new Error("AI response format invalid (missing array)");
    }

    let trends: Trend[];
    try {
      trends = JSON.parse(text) as Trend[];
    } catch (e) {
      console.error("Failed to parse JSON:", text);
      throw new Error("AI returned malformed JSON");
    }

    if (!Array.isArray(trends)) {
      return [];
    }

    // --- Defensive Post-Processing ---
    // Ensure every field exists to prevent UI crashes
    return trends.map((t, index) => {
      // Simulate history if missing
      const safeHistory = (t.history && t.history.length > 0) 
        ? t.history 
        : Array.from({ length: 5 }).map((_, i) => ({
            date: `Day -${4-i}`,
            score: Math.max(10, Math.floor((t.score || 50) * (0.8 + Math.random() * 0.4)))
          }));

      // Sanitize sources
      const safeSources = Array.isArray(t.sources) ? t.sources.map(s => ({
        title: s.title || "Unknown Headline",
        url: s.url || "#",
        sourceName: s.sourceName || "Web Source"
      })) : [];

      return {
        id: t.id || `trend-${Date.now()}-${index}`,
        title: t.title || "Untitled Trend",
        summary: t.summary || "No summary available.",
        score: typeof t.score === 'number' ? t.score : 50,
        category: t.category || 'Lifestyle',
        velocity: t.velocity || 'Stable',
        reasoning: t.reasoning || "No reasoning provided.",
        location: t.location || filters.country,
        sources: safeSources,
        history: safeHistory
      } as Trend;
    });

  } catch (error) {
    console.error("Error detecting trends:", error);
    throw error;
  }
};

