import { GoogleGenAI, Type, Schema } from "@google/genai";
import { FilterState, Trend } from "../types";

// Using 'gemini-3-flash-preview' which supports Thinking Config and Search
const MODEL_NAME = 'gemini-3-flash-preview'; 

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Detects trends by scraping Google Search and clustering results via Gemini.
 */
export const detectTrends = async (filters: FilterState): Promise<Trend[]> => {
  const { country, date, category } = filters;

  // 1. Dynamic Search Query Construction
  let searchQuery = `top news stories in ${country} today`;
  if (category !== 'All') {
    searchQuery = `trending ${category} news in ${country} today`;
  }
  if (date) {
    searchQuery += ` ${date}`;
  }

  // 2. Dynamic Source Context
  let sourceContext = 'Major national and international news outlets.';
  if (country === 'Malaysia') sourceContext = 'Sources: New Straits Times, The Star, Berita Harian, Says, Bernama.';
  if (country === 'Global') sourceContext = 'Sources: Reuters, BBC, Al Jazeera, AP, Bloomberg.';

  // 3. Strict Prompting with Thinking Requirement
  const prompt = `
    You are a Senior Data Journalist. Your task is to identify exactly 5 distinct, high-impact news trends for the date: ${date}.

    STEP 1: SEARCH
    Use the 'googleSearch' tool to search for: "${searchQuery}".
    - You must read the search results carefully.
    - EXTRACT real URLs and Headlines. Do not make them up.

    STEP 2: ANALYZE & CLUSTER
    - Group the search results into 5 distinct "Trend" topics.
    - For each trend, synthesize a 'summary' (2-3 sentences) explaining WHAT happened and WHY it matters.
    - Assign a 'velocity' based on how recent the articles are (Rising = <12h, Stable = <24h).

    STEP 3: GENERATE JSON
    Return a strictly formatted JSON array matching the schema below.

    CRITICAL RULES:
    - "sources": MUST contain the ACTUAL URLs found in the search. If you can't find a URL, do not include the source.
    - "summary": MUST be non-empty and descriptive.
    - "location": If the news is specific to a city (e.g., "Flood in Johor"), put "Johor". If national, put "${country}".
  `;

  const responseSchema: Schema = {
    type: Type.ARRAY,
    items: {
      type: Type.OBJECT,
      properties: {
        id: { type: Type.STRING },
        title: { type: Type.STRING },
        summary: { type: Type.STRING },
        score: { type: Type.NUMBER },
        category: { type: Type.STRING, enum: ['Politics', 'Tech', 'Business', 'Lifestyle', 'Entertainment'] },
        velocity: { type: Type.STRING, enum: ['Rising', 'Stable', 'Declining'] },
        reasoning: { type: Type.STRING },
        location: { type: Type.STRING },
        sources: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              url: { type: Type.STRING },
              sourceName: { type: Type.STRING },
            }
          }
        },
        history: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              date: { type: Type.STRING },
              score: { type: Type.NUMBER }
            }
          }
        }
      }
    }
  };

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        // ENABLE THINKING: This is the key fix. It gives the model a token budget 
        // to process search results before generating the JSON.
        thinkingConfig: { thinkingBudget: 1024 } 
      }
    });

    let text = response.text;
    if (!text) throw new Error("No data returned from AI");

    // --- Robust JSON Extraction ---
    text = text.replace(/```json/g, "").replace(/```/g, "").trim();
    const firstBracket = text.indexOf('[');
    const lastBracket = text.lastIndexOf(']');

    if (firstBracket !== -1 && lastBracket !== -1) {
      text = text.substring(firstBracket, lastBracket + 1);
    } else {
      throw new Error("AI did not return a valid JSON array.");
    }

    let trends: Trend[];
    try {
      trends = JSON.parse(text) as Trend[];
    } catch (e) {
      console.error("JSON Parse Error:", text);
      throw new Error("Failed to parse AI response.");
    }

    if (!Array.isArray(trends)) return [];

    // --- Post-Processing & Validation ---
    return trends.map((t, index) => {
      // 1. Ensure Summary exists
      const safeSummary = (t.summary && t.summary.length > 15) 
        ? t.summary 
        : `News signal detected regarding "${t.title}". Click sources for details.`;

      // 2. Validate Sources
      let validSources: any[] = [];
      if (Array.isArray(t.sources)) {
        validSources = t.sources
          .filter(s => s.url && s.url.startsWith('http')) 
          .map(s => ({
            title: s.title || "Read Article",
            url: s.url,
            sourceName: s.sourceName || new URL(s.url).hostname.replace('www.', '')
          }));
      }

      // 3. Populate History if missing
      const safeHistory = (t.history && t.history.length > 0) 
        ? t.history 
        : Array.from({ length: 5 }).map((_, i) => ({
            date: `Day -${4-i}`,
            score: Math.max(10, Math.floor((t.score || 50) * (0.8 + Math.random() * 0.4)))
          }));

      return {
        id: t.id || `trend-${Date.now()}-${index}`,
        title: t.title || "Untitled Signal",
        summary: safeSummary,
        score: typeof t.score === 'number' ? t.score : 50,
        category: t.category || (category === 'All' ? 'Business' : category),
        velocity: t.velocity || 'Stable',
        reasoning: t.reasoning || "Trend detected based on current search volume.",
        location: t.location || filters.country,
        sources: validSources,
        history: safeHistory
      } as Trend;
    });

  } catch (error) {
    console.error("Error detecting trends:", error);
    throw error;
  }
};

