          }
        },
        history: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              date: { type: Type.STRING },
              score: { type: Type.NUMBER }
            }
          }
        }
      }
    }
  };

  try {
    const response = await ai.models.generateContent({
      model: MAIN_MODEL,
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        thinkingConfig: { thinkingBudget: 1024 } 
      }
    });

    let text = response.text;
    if (!text) throw new Error("No data returned from AI");

    text = text.replace(/```json/g, "").replace(/```/g, "").trim();
    const firstBracket = text.indexOf('[');
    const lastBracket = text.lastIndexOf(']');

    if (firstBracket !== -1 && lastBracket !== -1) {
      text = text.substring(firstBracket, lastBracket + 1);
    } else {
      throw new Error("AI did not return a valid JSON array.");
    }

    let trends: Trend[];
    try {
      trends = JSON.parse(text) as Trend[];
    } catch (e) {
      console.error("JSON Parse Error:", text);
      throw new Error("Failed to parse AI response.");
    }

    if (!Array.isArray(trends)) return [];

    return trends.map((t, index) => {
      const safeSummary = (t.summary && t.summary.length > 15) 
        ? t.summary 
        : `News signal detected regarding "${t.title}". Click sources for details.`;

      let validSources: any[] = [];
      if (Array.isArray(t.sources)) {
        validSources = t.sources
          .filter(s => s.url && s.url.startsWith('http')) 
          .map(s => ({
            title: s.title || "Read Article",
            url: s.url,
            sourceName: s.sourceName || new URL(s.url).hostname.replace('www.', '')
          }));
      }

      const safeHistory = (t.history && t.history.length > 0) 
        ? t.history 
        : Array.from({ length: 5 }).map((_, i) => ({
            date: `Day -${4-i}`,
            score: Math.max(10, Math.floor((t.score || 50) * (0.8 + Math.random() * 0.4)))
          }));

      return {
        id: t.id || `trend-${Date.now()}-${index}`,
        title: t.title || "Untitled Signal",
        summary: safeSummary,
        score: typeof t.score === 'number' ? t.score : 50,
        category: t.category || (category === 'All' ? 'Business' : category),
        velocity: t.velocity || 'Stable',
        reasoning: t.reasoning || "Trend detected based on current search volume.",
        location: t.location || filters.country,
        sources: validSources,
        history: safeHistory
      } as Trend;
    });

  } catch (error) {
    console.error("Error detecting trends:", error);
    throw error;
  }
};

/**
 * Maps Grounding: Finds the specific location URI for a trend.
 */
export const getTrendLocation = async (trendTitle: string, country: string): Promise<{uri: string, name: string} | null> => {
  try {
    const prompt = `Where is the event "${trendTitle}" happening in ${country}? If it's a general topic, find the capital city or most relevant location.`;

    const response = await ai.models.generateContent({
      model: MAPS_MODEL,
      contents: prompt,
      config: {
        tools: [{ googleMaps: {} }],
      },
    });

    // Extract grounding chunks
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    if (chunks && chunks.length > 0) {
      // Find the first chunk that has map data
      const mapChunk = chunks.find((c: any) => c.web?.uri && c.web?.uri.includes('google.com/maps'));

      if (mapChunk && mapChunk.web) {
        return {
          uri: mapChunk.web.uri,
          name: mapChunk.web.title || trendTitle
        };
      }
    }
    return null;
  } catch (error) {
    console.error("Maps grounding error:", error);
    return null;
  }
};

/**
 * TTS: Generates an audio briefing for the trend.
 */
export const generateAudioBriefing = async (text: string): Promise<AudioBuffer> => {
  const response = await ai.models.generateContent({
    model: TTS_MODEL,
    contents: [{ parts: [{ text: `Here is your Trend Pulse briefing. ${text}` }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: 'Kore' },
        },
      },
    },
  });

  const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  if (!base64Audio) throw new Error("No audio data returned");

  // Decode raw PCM
  const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({sampleRate: 24000});
  const audioBuffer = await decodeAudioData(
    decode(base64Audio),
    audioContext,
    24000,
    1
  );

  return audioBuffer;
};

// --- Audio Helpers ---

function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

import React, { useState, useEffect } from 'react';
import { Trend } from '../types';
import { ArrowUpRight, Globe, MessageSquare, AlertCircle, Play, Loader2, MapPin, Pause } from 'lucide-react';
import TrendChart from './TrendChart';
import TrendMap from './TrendMap';
import { generateAudioBriefing, getTrendLocation } from '../services/geminiService';

interface TrendDetailProps {
  trend: Trend;
  onClose: () => void;
}

const TrendDetail: React.FC<TrendDetailProps> = ({ trend, onClose }) => {
  // Audio State
  const [isPlaying, setIsPlaying] = useState(false);
  const [isAudioLoading, setIsAudioLoading] = useState(false);
  const [audioContext, setAudioContext] = useState<AudioContext | null>(null);
  const [audioSource, setAudioSource] = useState<AudioBufferSourceNode | null>(null);

  // Maps Grounding State
  const [groundedLocation, setGroundedLocation] = useState<{uri: string, name: string} | null>(null);
  const [isMapLoading, setIsMapLoading] = useState(false);

  // Reset states when trend changes
  useEffect(() => {
    setIsPlaying(false);
    if (audioSource) {
      try { audioSource.stop(); } catch (e) {}
    }
    setAudioContext(null);
    setAudioSource(null);
    setGroundedLocation(null);

    // Fetch Map Grounding
    const fetchMap = async () => {
      setIsMapLoading(true);
      const data = await getTrendLocation(trend.title, trend.location || 'Global');
      setGroundedLocation(data);
      setIsMapLoading(false);
    };
    fetchMap();

    // Cleanup on unmount/change
    return () => {
       if (audioContext) audioContext.close();
    };
  }, [trend.id]);

  const handlePlayAudio = async () => {
    if (isPlaying) {
      if (audioSource) {
        audioSource.stop();
        setIsPlaying(false);
      }
      return;
    }

    setIsAudioLoading(true);
    try {
      const buffer = await generateAudioBriefing(trend.summary);

      const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
      const source = ctx.createBufferSource();
      source.buffer = buffer;
      source.connect(ctx.destination);

      source.onended = () => setIsPlaying(false);
      source.start(0);

      setAudioContext(ctx);
      setAudioSource(source);
      setIsPlaying(true);
    } catch (error) {
      console.error("Audio playback failed", error);
      alert("Could not generate audio briefing.");
    } finally {
      setIsAudioLoading(false);
    }
