    return keywords.some(k => text.includes(k));
  };

  return (
    <div className="flex flex-col lg:flex-row gap-6">
      {/* Left Column: Analytics & Info */}
      <div className="flex-1 space-y-6 min-w-0">

        {/* Header Card */}
