                  {trend.velocity}
                </span>
                <span className="text-xs text-slate-400 font-mono">ID: {trend.id}</span>
              </div>
              <h2 className="text-xl sm:text-2xl font-bold text-slate-900 leading-tight">{trend.title}</h2>
            </div>
            <div className="flex flex-col items-end shrink-0 ml-4">
                <div className="text-3xl font-black text-slate-800">{trend.score}</div>
                <div className="text-xs text-slate-500 uppercase font-semibold text-right">Signal<br/>Score</div>
            </div>
          </div>

          <div className="text-slate-700 mb-6 leading-relaxed text-sm sm:text-base border-l-4 border-blue-500 pl-4 bg-slate-50 py-2 rounded-r-lg">
             {trend.summary || "Summary unavailable. Please check the source links for more details."}
          </div>

          <div className="flex flex-wrap items-center gap-4">
            <button 
              onClick={handlePlayAudio}
              disabled={isAudioLoading}
              className={`flex items-center gap-2 px-4 py-2 rounded-lg font-semibold text-sm transition-all ${
                isPlaying 
                  ? 'bg-red-50 text-red-600 border border-red-200' 
                  : 'bg-slate-100 text-slate-700 border border-slate-200 hover:bg-slate-200'
              }`}
            >
              {isAudioLoading ? <Loader2 size={16} className="animate-spin" /> : (isPlaying ? <Pause size={16} /> : <Play size={16} />)}
