             <button onClick={() => setShowImageModal(false)} className="absolute top-4 right-4 bg-white/50 hover:bg-white rounded-full p-1 text-slate-800 transition-colors z-10">
               <X size={20} />
             </button>
             {isImageLoading ? (
               <div className="aspect-video flex flex-col items-center justify-center bg-slate-100 rounded-lg">
                 <Loader2 size={40} className="text-blue-600 animate-spin mb-4" />
