                    ${selectedTrendId === trend.id 
                      ? 'bg-blue-600 border-blue-600 shadow-md transform scale-[1.02]' 
                      : 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700 hover:border-blue-300 dark:hover:border-slate-500 hover:shadow-sm'
                    }
                  `}
                >
                  <div className="flex justify-between items-start mb-2">
                    <span className={`text-[10px] font-bold uppercase tracking-wider px-1.5 py-0.5 rounded ${
                      selectedTrendId === trend.id ? 'bg-blue-500 text-white' : 'bg-slate-100 dark:bg-slate-700 text-slate-500 dark:text-slate-300'
                    }`}>
                      {trend.category}
                    </span>
                    <span className={`text-xs font-bold ${
                      selectedTrendId === trend.id ? 'text-blue-200' : 'text-slate-400 dark:text-slate-500'
                    }`}>
                      {trend.score}/100
                    </span>
                  </div>
                  <h3 className={`font-semibold text-sm mb-1 line-clamp-2 ${
                     selectedTrendId === trend.id ? 'text-white' : 'text-slate-800 dark:text-slate-100 group-hover:text-blue-600 dark:group-hover:text-blue-400'
                  }`}>
                    {trend.title}
                  </h3>
                  <div className={`flex items-center gap-2 mt-2 text-xs ${
                    selectedTrendId === trend.id ? 'text-blue-200' : 'text-slate-400 dark:text-slate-500'
                  }`}>
                     <span>{trend.sources.length} sources</span>
                     <span>•</span>
                     <span>{trend.velocity}</span>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Right Area: Detail View */}
          <div ref={detailViewRef} className="col-span-12 md:col-span-8 lg:col-span-9">
            {selectedTrend ? (
               <TrendDetail trend={selectedTrend} onClose={() => setSelectedTrendId(null)} isDarkMode={isDarkMode} />
            ) : (
               <div className="min-h-[300px] h-full bg-slate-100 dark:bg-slate-800/50 rounded-2xl border-2 border-dashed border-slate-200 dark:border-slate-700 flex flex-col items-center justify-center text-slate-400 dark:text-slate-500 p-8">
                  <div className="w-16 h-16 bg-white dark:bg-slate-800 rounded-full shadow-sm flex items-center justify-center mb-4">
                     <TrendingUp size={32} className="text-slate-300 dark:text-slate-600" />
                  </div>
                  <h3 className="text-lg font-semibold text-slate-500 dark:text-slate-400">Select a signal to analyze</h3>
                  <p className="text-sm max-w-md text-center mt-2">
                    AI will explain the trend velocity, provide reasoning, and map the geolocation.
                  </p>
               </div>
            )}
          </div>

        </div>
      </main>

      {/* Chatbot Widget */}
      <ChatBot />
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Trend } from '../types';
import { ArrowUpRight, Globe, MessageSquare, AlertCircle, Play, Loader2, MapPin, Pause, ImageIcon, X } from 'lucide-react';
import TrendChart from './TrendChart';
import TrendMap from './TrendMap';
import { generateAudioBriefing, getTrendLocation, generateTrendImage } from '../services/geminiService';

interface TrendDetailProps {
  trend: Trend;
  onClose: () => void;
  isDarkMode?: boolean;
}

const TrendDetail: React.FC<TrendDetailProps> = ({ trend, onClose, isDarkMode = false }) => {
  // Audio State
  const [isPlaying, setIsPlaying] = useState(false);
  const [isAudioLoading, setIsAudioLoading] = useState(false);
  const [audioContext, setAudioContext] = useState<AudioContext | null>(null);
  const [audioSource, setAudioSource] = useState<AudioBufferSourceNode | null>(null);

  // Maps Grounding State
  const [groundedLocation, setGroundedLocation] = useState<{uri: string, name: string} | null>(null);
  const [isMapLoading, setIsMapLoading] = useState(false);

  // Image Gen State
  const [generatedImage, setGeneratedImage] = useState<string | null>(null);
  const [isImageLoading, setIsImageLoading] = useState(false);
  const [showImageModal, setShowImageModal] = useState(false);

  // Reset states when trend changes
  useEffect(() => {
    setIsPlaying(false);
    if (audioSource) {
      try { audioSource.stop(); } catch (e) {}
    }
    setAudioContext(null);
    setAudioSource(null);
    setGroundedLocation(null);
    setGeneratedImage(null);
    setShowImageModal(false);

    // Fetch Map Grounding
    const fetchMap = async () => {
      setIsMapLoading(true);
      const data = await getTrendLocation(trend.title, trend.location || 'Global');
      setGroundedLocation(data);
      setIsMapLoading(false);
    };
    fetchMap();

    // Cleanup on unmount/change
    return () => {
       if (audioContext) audioContext.close();
    };
  }, [trend.id]);

  const handlePlayAudio = async () => {
    if (isPlaying) {
      if (audioSource) {
        audioSource.stop();
        setIsPlaying(false);
      }
      return;
    }

    setIsAudioLoading(true);
    try {
      const buffer = await generateAudioBriefing(trend.summary);

      const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
      const source = ctx.createBufferSource();
      source.buffer = buffer;
      source.connect(ctx.destination);

      source.onended = () => setIsPlaying(false);
      source.start(0);

      setAudioContext(ctx);
      setAudioSource(source);
      setIsPlaying(true);
    } catch (error) {
      console.error("Audio playback failed", error);
      alert("Could not generate audio briefing.");
    } finally {
      setIsAudioLoading(false);
    }
  };

  const handleViewImage = async () => {
    setShowImageModal(true);
    if (generatedImage) return; // Already generated

    // KEY CHECK LOGIC
    try {
      if ((window as any).aistudio) {
        const hasKey = await (window as any).aistudio.hasSelectedApiKey();
        if (!hasKey) {
          await (window as any).aistudio.openSelectKey();
          // After returning from selection, we assume success or user cancelled. 
          // We check again or just proceed to try. 
          // Note: The new key is auto-injected into process.env.API_KEY if using the standard environment
        }
      }
    } catch (e) {
      console.warn("AI Studio key check failed, proceeding anyway", e);
    }

    setIsImageLoading(true);
    try {
      const base64 = await generateTrendImage(trend.title, trend.summary);
      setGeneratedImage(base64);
    } catch (error) {
      console.error("Image generation failed", error);
      // If it fails with "Requested entity was not found" or similar auth error
      if (JSON.stringify(error).includes("found") || JSON.stringify(error).includes("permission")) {
         try {
           await (window as any).aistudio.openSelectKey();
           alert("Please select a valid paid API key and try again.");
         } catch(e) {
            alert("Failed to generate image. Ensure you have a paid API key selected.");
         }
      } else {
         alert("Failed to generate image.");
      }
      setShowImageModal(false);
    } finally {
      setIsImageLoading(false);
    }
  };

  const getVelocityColor = (v: string) => {
    switch (v) {
      case 'Rising': return 'bg-green-100 text-green-700 border-green-200 dark:bg-green-900/30 dark:text-green-300 dark:border-green-800';
      case 'Declining': return 'bg-red-100 text-red-700 border-red-200 dark:bg-red-900/30 dark:text-red-300 dark:border-red-800';
      default: return 'bg-gray-100 text-gray-700 border-gray-200 dark:bg-slate-700 dark:text-slate-300 dark:border-slate-600';
    }
  };

  const isMediaPrima = (name: string, url: string) => {
    const safeName = name || '';
    const safeUrl = url || '';
    const keywords = [
      'media prima', 'nst', 'new straits times', 'bharian', 'berita harian', 
      'hmetro', 'harian metro', 'says', 'ohbulan', 'seismik', 'tonton', 'tv3', '8tv', 'tv9'
    ];
    const text = `${safeName} ${safeUrl}`.toLowerCase();
    return keywords.some(k => text.includes(k));
  };

  return (
    <div className="flex flex-col lg:flex-row gap-6 relative">
      {/* Image Modal */}
      {showImageModal && (
        <div className="absolute inset-0 z-50 flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-900/50 backdrop-blur-sm rounded-2xl" onClick={() => setShowImageModal(false)}></div>
          <div className="relative bg-white dark:bg-slate-800 rounded-xl shadow-2xl p-2 w-full max-w-2xl overflow-hidden transition-colors">
             <button onClick={() => setShowImageModal(false)} className="absolute top-4 right-4 bg-white/50 hover:bg-white dark:bg-black/50 dark:hover:bg-black rounded-full p-1 text-slate-800 dark:text-slate-200 transition-colors z-10">
               <X size={20} />
             </button>
             {isImageLoading ? (
               <div className="aspect-video flex flex-col items-center justify-center bg-slate-100 dark:bg-slate-700 rounded-lg">
                 <Loader2 size={40} className="text-blue-600 animate-spin mb-4" />
                 <p className="text-slate-500 dark:text-slate-300 font-medium animate-pulse">Generating AI Image...</p>
                 <p className="text-xs text-slate-400 dark:text-slate-500 mt-2">Using Gemini Nano Banana Pro</p>
               </div>
             ) : (
               generatedImage && <img src={generatedImage} alt="AI Generated Trend Visual" className="w-full h-auto rounded-lg" />
             )}
          </div>
        </div>
      )}

      {/* Left Column: Analytics & Info */}
      <div className="flex-1 space-y-6 min-w-0">

        {/* Header Card */}
        <div className="bg-white dark:bg-slate-900 p-4 sm:p-6 rounded-xl shadow-sm border border-slate-200 dark:border-slate-800 transition-colors">
          <div className="flex justify-between items-start mb-4">
            <div>
              <div className="flex items-center gap-2 mb-2">
                <span className={`px-2 py-0.5 rounded text-xs font-semibold uppercase tracking-wider ${getVelocityColor(trend.velocity)}`}>
                  {trend.velocity}
                </span>
                <span className="text-xs text-slate-400 dark:text-slate-500 font-mono">ID: {trend.id}</span>
              </div>
              <h2 className="text-xl sm:text-2xl font-bold text-slate-900 dark:text-white leading-tight">{trend.title}</h2>
            </div>
            <div className="flex flex-col items-end shrink-0 ml-4">
                <div className="text-3xl font-black text-slate-800 dark:text-slate-200">{trend.score}</div>
                <div className="text-xs text-slate-500 dark:text-slate-400 uppercase font-semibold text-right">Signal<br/>Score</div>
            </div>
          </div>

          <div className="text-slate-700 dark:text-slate-300 mb-6 leading-relaxed text-sm sm:text-base border-l-4 border-blue-500 pl-4 bg-slate-50 dark:bg-slate-800/50 py-2 rounded-r-lg">
             {trend.summary || "Summary unavailable. Please check the source links for more details."}
          </div>

          <div className="flex flex-wrap items-center gap-4">
            <button 
              onClick={handlePlayAudio}
              disabled={isAudioLoading}
              className={`flex items-center gap-2 px-4 py-2 rounded-lg font-semibold text-sm transition-all ${
                isPlaying 
                  ? 'bg-red-50 text-red-600 border border-red-200 dark:bg-red-900/20 dark:text-red-400 dark:border-red-800' 
                  : 'bg-slate-100 text-slate-700 border border-slate-200 hover:bg-slate-200 dark:bg-slate-800 dark:text-slate-300 dark:border-slate-700 dark:hover:bg-slate-700'
              }`}
            >
              {isAudioLoading ? <Loader2 size={16} className="animate-spin" /> : (isPlaying ? <Pause size={16} /> : <Play size={16} />)}
              {isPlaying ? 'Stop Briefing' : 'Listen to Briefing'}
            </button>

            <button 
              onClick={handleViewImage}
              className="flex items-center gap-2 px-4 py-2 rounded-lg font-semibold text-sm bg-purple-100 text-purple-700 border border-purple-200 hover:bg-purple-200 dark:bg-purple-900/30 dark:text-purple-300 dark:border-purple-800 dark:hover:bg-purple-900/50 transition-all"
            >
              <ImageIcon size={16} />
              View AI Image
            </button>
          </div>

          <div className="mt-6 bg-amber-50 dark:bg-amber-900/10 border border-amber-200 dark:border-amber-800/30 rounded-lg p-4">
            <h4 className="text-sm font-bold text-amber-900 dark:text-amber-500 flex items-center gap-2 mb-2">
              <AlertCircle size={16} /> Why it matters
            </h4>
            <p className="text-sm text-amber-800 dark:text-amber-200/80 leading-relaxed">
              {trend.reasoning || "High engagement detected across multiple media outlets."}
            </p>
          </div>
        </div>

        {/* Chart Card */}
        <div className="bg-white dark:bg-slate-900 p-4 sm:p-6 rounded-xl shadow-sm border border-slate-200 dark:border-slate-800 overflow-hidden transition-colors">
            <h3 className="font-semibold text-slate-800 dark:text-slate-200 mb-2">Signal Velocity (Last 5 Days)</h3>
            <TrendChart data={trend.history} color={trend.velocity === 'Rising' ? '#22c55e' : '#3b82f6'} isDarkMode={isDarkMode} />
        </div>

        {/* Sources Card */}
        <div className="bg-white dark:bg-slate-900 p-4 sm:p-6 rounded-xl shadow-sm border border-slate-200 dark:border-slate-800 transition-colors">
           <h3 className="font-semibold text-slate-800 dark:text-slate-200 mb-4 flex items-center gap-2">
             <Globe size={18} /> Signal Sources
           </h3>
           <div className="space-y-3">
             {trend.sources.map((source, idx) => (
               <a 
                 key={idx} 
                 href={source.url}
                 target="_blank"
                 rel="noopener noreferrer"
                 className="block group p-3 rounded-lg border border-slate-100 dark:border-slate-800 hover:border-blue-200 dark:hover:border-slate-600 hover:bg-blue-50 dark:hover:bg-slate-800 transition-all"
               >
                 <div className="flex justify-between items-start gap-2">
                    <span className="text-sm font-medium text-slate-700 dark:text-slate-300 group-hover:text-blue-700 dark:group-hover:text-blue-400 line-clamp-1 break-all sm:break-normal">
                        {source.title || "Read Full Article"}
                    </span>
                    <ArrowUpRight size={14} className="text-slate-300 dark:text-slate-600 group-hover:text-blue-500 opacity-0 group-hover:opacity-100 transition-opacity shrink-0" />
                 </div>
                 <div className="mt-1 flex flex-wrap items-center gap-2 text-xs text-slate-500 dark:text-slate-400">
                    <span className="font-semibold text-slate-600 dark:text-slate-400">{source.sourceName || "Source"}</span>
                    {isMediaPrima(source.sourceName, source.url) && (
                      <>
                        <span className="hidden sm:inline">•</span>
                        <span className="text-blue-600 dark:text-blue-400 font-bold block sm:inline mt-1 sm:mt-0">Media Prima Network</span>
                      </>
                    )}
                 </div>
               </a>
             ))}
             {trend.sources.length === 0 && (
                <div className="text-sm text-slate-400 italic p-4 text-center bg-slate-50 dark:bg-slate-800 rounded-lg">
                    Sources could not be automatically verified. Please perform a manual search for "{trend.title}".
                </div>
             )}
           </div>
        </div>
      </div>

      {/* Right Column: Visuals & Map */}
      <div className="w-full lg:w-80 flex flex-col gap-6 shrink-0">
         <div className="h-64 sm:h-80 w-full relative">
            <TrendMap 
              locationName={groundedLocation?.name || trend.location || ''} 
              trendTitle={trend.title} 
            />
            {/* Maps Grounding Overlay */}
            {groundedLocation && (
               <a 
                 href={groundedLocation.uri}
                 target="_blank"
                 rel="noopener noreferrer"
                 className="absolute bottom-10 left-4 right-4 bg-white/90 dark:bg-slate-900/90 backdrop-blur-sm p-3 rounded-lg shadow-lg border border-slate-200 dark:border-slate-700 text-xs flex items-center justify-between group hover:bg-white dark:hover:bg-slate-800 transition-all z-10"
               >
                  <div className="flex items-center gap-2 text-slate-700 dark:text-slate-200">
                    <MapPin size={16} className="text-red-500" />
                    <span className="font-semibold truncate max-w-[150px]">{groundedLocation.name}</span>
                  </div>
                  <ArrowUpRight size={14} className="text-slate-400 group-hover:text-blue-500" />
               </a>
            )}
            {isMapLoading && (
               <div className="absolute top-2 right-2 bg-white/80 dark:bg-slate-800/80 p-1.5 rounded-full shadow-sm animate-pulse">
                  <Loader2 size={14} className="animate-spin text-slate-500 dark:text-slate-300" />
               </div>
            )}
         </div>

         {/* Context Card */}
         <div className="bg-gradient-to-br from-indigo-600 to-purple-700 rounded-xl shadow-lg p-6 text-white">
            <h3 className="font-bold text-lg mb-2 flex items-center gap-2">
                <MessageSquare size={18} />
                Analyst Note
            </h3>
            <p className="text-indigo-100 text-sm leading-relaxed mb-4">
                This trend has clustered across {trend.sources.length + 3} distinct data points today.
            </p>
            <div className="flex flex-wrap gap-2">
                <span className="px-2 py-1 bg-white/10 rounded text-xs border border-white/20">High Engagement</span>
                <span className="px-2 py-1 bg-white/10 rounded text-xs border border-white/20">Sentiment: Mixed</span>
            </div>
         </div>
      </div>
    </div>
  );
};

export default TrendDetail;

import React from 'react';
import { XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Area, AreaChart } from 'recharts';
import { TrendDataPoint } from '../types';

interface TrendChartProps {
  data: TrendDataPoint[];
  color?: string;
  isDarkMode?: boolean;
}

const TrendChart: React.FC<TrendChartProps> = ({ data, color = "#3b82f6", isDarkMode = false }) => {
  if (!data || data.length === 0) {
    return <div className="h-48 flex items-center justify-center text-gray-400 text-sm">No historical data</div>;
  }

  const gridColor = isDarkMode ? "#334155" : "#e2e8f0"; // slate-700 vs slate-200
  const axisColor = isDarkMode ? "#94a3b8" : "#64748b"; // slate-400 vs slate-500
  const tooltipBg = isDarkMode ? "#1e293b" : "#fff"; // slate-800 vs white
  const tooltipBorder = isDarkMode ? "#334155" : "#e2e8f0";
  const tooltipText = isDarkMode ? "#f1f5f9" : "#1e293b";

  return (
    <div className="h-48 w-full mt-4" style={{ minWidth: 0 }}>
      <ResponsiveContainer width="100%" height="100%">
        <AreaChart
          data={data}
          margin={{
            top: 5,
            right: 0,
            left: 0,
            bottom: 0,
          }}
        >
          <defs>
            <linearGradient id="colorScore" x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor={color} stopOpacity={0.3}/>
              <stop offset="95%" stopColor={color} stopOpacity={0}/>
            </linearGradient>
          </defs>
          <CartesianGrid strokeDasharray="3 3" vertical={false} stroke={gridColor} />
          <XAxis 
            dataKey="date" 
            tick={{fontSize: 10, fill: axisColor}} 
            axisLine={false}
            tickLine={false}
          />
          <YAxis 
            hide 
            domain={[0, 100]} 
          />
          <Tooltip 
            contentStyle={{ 
              backgroundColor: tooltipBg, 
              borderRadius: '8px', 
              border: `1px solid ${tooltipBorder}`, 
              fontSize: '12px',
              color: tooltipText
            }}
            itemStyle={{ color: tooltipText }}
            labelStyle={{ color: axisColor }}
          />
          <Area 
            type="monotone" 
            dataKey="score" 
            stroke={color} 
            strokeWidth={2}
            fillOpacity={1} 
            fill="url(#colorScore)" 
          />
        </AreaChart>
      </ResponsiveContainer>
    </div>
  );
};

export default TrendChart;

import React from 'react';
import { MapPin } from 'lucide-react';

interface TrendMapProps {
  locationName: string;
  trendTitle: string;
}

const TrendMap: React.FC<TrendMapProps> = ({ locationName, trendTitle }) => {
  // Determine if this is a global trend
  const isGlobal = locationName === 'Global' || locationName === 'World';

  // --- Smart Zoom Logic ---
  // isGlobal -> Zoom 2 (World View)
  // Standard -> Zoom 5 (Country/Region View) - Safer default than 11 (Street view)
  const query = encodeURIComponent(isGlobal ? "World" : locationName || "Global");
  const zoom = isGlobal ? 2 : 5; 

  // Embed API URL
  const mapSrc = `https://maps.google.com/maps?q=${query}&t=&z=${zoom}&ie=UTF8&iwloc=&output=embed`;

  return (
    <div className="bg-white dark:bg-slate-900 rounded-xl shadow-sm border border-slate-200 dark:border-slate-800 overflow-hidden flex flex-col h-full transition-colors">
      <div className="p-4 border-b border-slate-100 dark:border-slate-800 flex justify-between items-center bg-slate-50 dark:bg-slate-800/50">
        <h3 className="font-semibold text-slate-800 dark:text-slate-200 flex items-center gap-2">
          <MapPin size={18} className="text-red-500" />
          Location Context
        </h3>
      </div>

      <div className="flex-1 relative bg-slate-100 dark:bg-slate-800">
        {locationName ? (
           <iframe 
             width="100%" 
             height="100%" 
             src={mapSrc} 
             frameBorder="0" 
             scrolling="no" 
             marginHeight={0} 
             marginWidth={0}
             title={`Map of ${locationName}`}
             className="absolute inset-0 w-full h-full grayscale-[0.2]" // Optional: slightly desaturate map to fit design better
           />
        ) : (
          <div className="flex items-center justify-center h-full text-slate-400 text-sm">
            No specific location data
          </div>
        )}
      </div>

      <div className="p-3 bg-white dark:bg-slate-900 border-t border-slate-100 dark:border-slate-800 text-xs text-slate-500 dark:text-slate-400 flex justify-between">
         <span>{locationName || "Global"}</span>
         <span className="text-slate-400 italic">Live Map</span>
      </div>
    </div>
  );
};

export default TrendMap;

import React, { useState, useRef, useEffect } from 'react';
import { MessageCircle, X, Send, Bot, User } from 'lucide-react';
import { ChatMessage } from '../types';
import { chatWithAnalyst } from '../services/geminiService';

const ChatBot: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([
    { id: '1', role: 'model', text: 'Hello! I am your TrendPulse Analyst. Ask me anything about the news trends.', timestamp: new Date() }
  ]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isOpen]);

  const handleSend = async () => {
    if (!input.trim() || loading) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: input,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setLoading(true);

    try {
      const history = messages.map(m => ({ role: m.role, text: m.text }));
      const responseText = await chatWithAnalyst(userMsg.text, history);

      const botMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: responseText || "I couldn't process that request.",
        timestamp: new Date()
      };
      setMessages(prev => [...prev, botMsg]);
    } catch (error) {
      console.error(error);
      const errorMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: "Sorry, I'm having trouble connecting to the network right now.",
        timestamp: new Date()
      };
      setMessages(prev => [...prev, errorMsg]);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="fixed bottom-6 right-6 z-50 flex flex-col items-end">
      {/* Chat Window */}
      {isOpen && (
        <div className="bg-white dark:bg-slate-900 rounded-2xl shadow-2xl border border-slate-200 dark:border-slate-800 w-80 sm:w-96 h-[500px] mb-4 flex flex-col overflow-hidden animate-in slide-in-from-bottom-10 fade-in duration-200 transition-colors">
