        <div className="absolute inset-0 z-50 flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-900/50 backdrop-blur-sm rounded-2xl" onClick={() => setShowImageModal(false)}></div>
          <div className="relative bg-white dark:bg-slate-800 rounded-xl shadow-2xl p-2 w-full max-w-2xl overflow-hidden transition-colors">
             <button onClick={() => setShowImageModal(false)} className="absolute top-4 right-4 bg-white/50 hover:bg-white dark:bg-black/50 dark:hover:bg-black rounded-full p-1 text-slate-800 dark:text-slate-200 transition-colors z-10">
               <X size={20} />
             </button>
             {isImageLoading ? (
               <div className="aspect-video flex flex-col items-center justify-center bg-slate-100 dark:bg-slate-700 rounded-lg">
                 <Loader2 size={40} className="text-blue-600 animate-spin mb-4" />
                 <p className="text-slate-500 dark:text-slate-300 font-medium animate-pulse">Generating AI Image...</p>
                 <p className="text-xs text-slate-400 dark:text-slate-500 mt-2">Using Gemini Flash Image (Standard)</p>
               </div>
             ) : (
               generatedImage && <img src={generatedImage} alt="AI Generated Trend Visual" className="w-full h-auto rounded-lg" />
             )}
          </div>
        </div>
